SELECT tblStation.TripYear, tblStation.Ship, tblStation.Trip, tblStation.Station, tblIndividual.KeyIndividual, tblLstSpecies.NameLatin, tblIndividualMeasure.IndividualMeasureType, tblIndividualMeasure.Attribute, tblIndividualMeasure.Measure
FROM tblStation INNER JOIN (tblStationSubGear INNER JOIN (tblLstSpecies INNER JOIN ((((tblCatch INNER JOIN tblCatchSub1 ON tblCatch.KeyCatch = tblCatchSub1.KeyCatch) INNER JOIN tblCatchSub2 ON tblCatchSub1.KeyCatchSub1 = tblCatchSub2.KeyCatchSub1) INNER JOIN tblIndividual ON tblCatchSub2.KeyCatchSub2 = tblIndividual.KeyCatchSub2) INNER JOIN tblIndividualMeasure ON tblIndividual.KeyIndividual = tblIndividualMeasure.KeyIndividual) ON tblLstSpecies.Species = tblCatchSub2.Species) ON tblStationSubGear.KeyStationSubGear = tblCatch.KeyStationSubGear) ON tblStation.KeyStation = tblStationSubGear.KeyStation
WHERE (((tblStation.TripYear)=2026) AND ((tblStation.Ship)="TA") AND ((tblStation.Trip)="2") AND ((tblStation.Station)=50) AND ((tblIndividual.KeyIndividual) In (SELECT [KeyIndividual] FROM [tblIndividualMeasure] WHERE [IndividualMeasureType]="ShrimpSex" AND [Attribute]="M")) AND ((tblLstSpecies.NameLatin)="Pandalus borealis"));
